import React, { useState, useEffect, useRef } from 'react';
import api from '../services/api';

const ReelsFeed = () => {
  const [reels, setReels] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [loading, setLoading] = useState(true);
  const videoRefs = useRef([]);
  const viewedReels = useRef(new Set());

  useEffect(() => {
    fetchReels();
  }, []);

  useEffect(() => {
    const activeVideo = videoRefs.current[currentIndex];
    if (activeVideo?.play) {
      activeVideo.play().catch(() => {});
    }

    // Track view when reel comes into view
    const currentReel = reels[currentIndex];
    if (currentReel && !viewedReels.current.has(currentReel._id)) {
      viewedReels.current.add(currentReel._id);
      api.post(`/reels/${currentReel._id}/view`).catch(() => {});
    }
  }, [currentIndex, reels]);

  const fetchReels = async () => {
    try {
      const res = await api.get('/reels');
      setReels(res.data);
      setLoading(false);
    } catch (error) {
      console.error('Error fetching reels:', error);
      setLoading(false);
    }
  };

  const handleScroll = (e) => {
    const scrollTop = e.target.scrollTop;
    const height = e.target.clientHeight;
    const newIndex = Math.round(scrollTop / height);

    if (newIndex !== currentIndex && newIndex >= 0 && newIndex < reels.length) {
      const previousVideo = videoRefs.current[currentIndex];
      if (previousVideo?.pause) {
        previousVideo.pause();
      }
      setCurrentIndex(newIndex);
    }
  };

  const handleLike = async (reelId) => {
    try {
      await api.post(`/reels/${reelId}/like`);
      // Update local state
      setReels(reels.map(reel =>
        reel._id === reelId ? { ...reel, likes: reel.likes + 1 } : reel
      ));
    } catch (error) {
      console.error('Error liking reel:', error);
    }
  };

  if (loading) {
    return (
      <div className="h-screen flex items-center justify-center bg-black text-white">
        <div className="flex flex-col items-center gap-4">
          <div className="w-10 h-10 border-2 border-purple-500 border-t-transparent rounded-full animate-spin" />
          <p className="text-gray-400 text-sm">Loading reels...</p>
        </div>
      </div>
    );
  }

  if (reels.length === 0) {
    return (
      <div className="h-screen flex items-center justify-center bg-black text-white">
        <p className="text-gray-400">No reels available.</p>
      </div>
    );
  }

  return (
    <div
      className="h-screen overflow-y-scroll snap-y snap-mandatory"
      onScroll={handleScroll}
    >
      {reels.map((reel, index) => (
        <div
          key={reel._id}
          className="h-screen snap-start relative flex items-center justify-center bg-black"
        >
          <video
            ref={(el) => (videoRefs.current[index] = el)}
            className="h-full w-auto max-w-full object-contain"
            src={`http://localhost:5000${reel.videoUrl}`}
            loop
            playsInline
          />

          <div className="absolute bottom-20 left-0 right-0 p-6 bg-gradient-to-t from-black">
            <h3 className="text-xl font-bold mb-2 text-white">{reel.title}</h3>
            <p className="text-sm text-gray-300 mb-4">by {reel.uploadedBy?.name}</p>
            <div className="flex items-center gap-4">
              <button
                onClick={() => handleLike(reel._id)}
                className="flex items-center gap-2 bg-white/20 px-4 py-2 rounded-full hover:bg-white/30 transition"
              >
                ❤️ {reel.likes}
              </button>
              <span className="bg-white/20 px-4 py-2 rounded-full text-gray-200">
                👁️ {reel.views}
              </span>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
};

export default ReelsFeed;
